236	    public void maybeUpdateModel() {
237	        for (TreeVisitor<?, P> afterVisit : getAfterVisit()) {
238	            if (afterVisit instanceof UpdateMavenModel) {
239	                return;
240	            }
241	        }
242	        doAfterVisit(new UpdateMavenModel<>());
243	    }
244	
245	    public boolean isPluginTag() {
246	        return isTag("plugin") && PLUGIN_MATCHER.matches(getCursor());
247	    }
248	
249	    public boolean isPluginTag(String groupId, @Nullable String artifactId) {
250	        return isPluginTag() && hasPluginGroupId(groupId) && hasPluginArtifactId(artifactId);
251	    }
252	
253	    public boolean isManagedPluginTag() {
254	        return isTag("plugin") && MANAGED_PLUGIN_MATCHER.matches(getCursor());
255	    }
256	
257	    private boolean hasPluginGroupId(String groupId) {
258	        Xml.Tag tag = getCursor().getValue();
259	        boolean isGroupIdFound = matchesGlob(tag.getChildValue("groupId").orElse("org.apache.maven.plugins"), groupId);
260	        if (!isGroupIdFound && getResolutionResult().getPom().getProperties() != null) {
261	            if (tag.getChildValue("groupId").isPresent() && tag.getChildValue("groupId").get().trim().startsWith("${")) {
262	                String propertyKey = tag.getChildValue("groupId").get().trim();
263	                String value = getResolutionResult().getPom().getValue(propertyKey);
264	                isGroupIdFound = matchesGlob(value, groupId);
265	            }
266	        }
267	        return isGroupIdFound;
268	    }
269	
270	    private boolean hasPluginArtifactId(@Nullable String artifactId) {
271	        Xml.Tag tag = getCursor().getValue();
272	        boolean isArtifactIdFound = tag.getChildValue("artifactId")
273	                .map(a -> matchesGlob(a, artifactId))
274	                .orElse(artifactId == null);
275	        if (!isArtifactIdFound && artifactId != null && getResolutionResult().getPom().getProperties() != null) {
276	            if (tag.getChildValue("artifactId").isPresent() && tag.getChildValue("artifactId").get().trim().startsWith("${")) {
277	                String propertyKey = tag.getChildValue("artifactId").get().trim();
278	                String value = getResolutionResult().getPom().getValue(propertyKey);
279	                isArtifactIdFound = matchesGlob(value, artifactId);
280	            }
281	        }
282	        return isArtifactIdFound;
283	    }
284	
285	
286	    public boolean isParentTag() {
287	        return isTag("parent") && PARENT_MATCHER.matches(getCursor());
288	    }
289	
290	    public boolean isProjectTag() {
291	        return isTag("project") && PROJECT_MATCHER.matches(getCursor());
292	    }
293	
294	    protected boolean isTag(String name) {
295	        // `XPathMatcher` is still a bit expensive
296	        return getCursor().getValue() instanceof Xml.Tag && name.equals(getCursor().<Xml.Tag>getValue().getName());
297	    }
298	
299	    protected Xml.Tag changeChildTagValue(Xml.Tag tag, String childTagName, @Nullable String newValue, P p) {
300	        return changeChildTagValue(tag, childTagName, newValue, false, p);
301	    }
302	
303	    protected Xml.Tag changeChildTagValue(Xml.Tag tag, String childTagName, @Nullable String newValue, @Nullable Boolean addPropertyIfMissing, P p) {
304	        Optional<Xml.Tag> childTag = tag.getChild(childTagName);
305	        if (childTag.isPresent()) {
306	            String oldValue = childTag.get().getValue().orElse(null);
307	            if (newValue != null && !newValue.equals(oldValue)) {
308	                if (isImplicitlyDefinedVersionProperty(oldValue)) {
309	                    // Implicitly defined version properties like ${project.parent.version} should never be changed
310	                    // as they represent intentional links to parent/project versions
311	                    return tag;
312	                }
313	                if (isProperty(oldValue)) {
314	                    MavenResolutionResult resolutionResult = getResolutionResult();
315	                    String propertyName = oldValue.substring(2, oldValue.length() - 1);
316	                    ResolvedPom pom = resolutionResult.getPom();
317	                    if (pom.getRequested().getProperties().containsKey(propertyName)) {
318	                        // The current REQUESTED pom already has a property, let's change the value of the property in the current file
319	                        doAfterVisit((TreeVisitor<?, P>) new ChangePropertyValue(propertyName, newValue, addPropertyIfMissing, false).getVisitor());
320	                    } else if (pom.getProperties().containsKey(propertyName)) {
321	                        // The combined pom knows about the property, but it is not originating from the current requested pom
322	                        boolean inheritsPropertyFromExternalParent = true;
323	                        while (resolutionResult.getParent() != null) {
324	                            resolutionResult = resolutionResult.getParent();
325	                            if (resolutionResult.getPom().getRequested().getProperties().containsKey(propertyName)) {
326	                                // We found an in-repo parent pom that creates this property, so we do not have to adapt this file as the other file will be adapted.
327	                                inheritsPropertyFromExternalParent = false;
328	                                break;
329	                            }
330	                        }
331	                        if (inheritsPropertyFromExternalParent) {
332	                            // We did not find a parent POM (external parents are not mapped on the resolution result's POM) in the repo,
333	                            // but the property exists so it must be a property that comes from an external parent pom,
334	                            // so we create the property in the current pom file in order to override its value
335	                            doAfterVisit((TreeVisitor<?, P>) new ChangePropertyValue(propertyName, newValue, true, false).getVisitor());
336	                        }
337	                    }
338	                } else {
339	                    tag = (Xml.Tag) new ChangeTagValueVisitor<>(childTag.get(), newValue).visitNonNull(tag, p);
340	                }
341	            }
342	        }
343	        return tag;
344	    }
345	
346	    @Contract("null -> false")
347	    protected boolean isImplicitlyDefinedVersionProperty(@Nullable String value) {
348	        return IMPLICITLY_DEFINED_VERSION_PROPERTIES.contains(value);
349	    }
350	
351	    @Contract("null -> false")
352	    protected boolean isProperty(@Nullable String value) {
353	        return !isImplicitlyDefinedVersionProperty(value) && ResolvedPom.placeholderHelper.hasPlaceholders(value);
354	    }
355	
356	    public @Nullable ResolvedDependency findDependency(Xml.Tag tag) {
357	        Map<Scope, List<ResolvedDependency>> dependencies = getResolutionResult().getDependencies();
358	        Scope scope = Scope.fromName(tag.getChildValue("scope").orElse("compile"));
359	        if (dependencies.containsKey(scope)) {
360	            for (ResolvedDependency resolvedDependency : dependencies.get(scope)) {
361	                Dependency req = resolvedDependency.getRequested();
362	                String reqGroup = req.getGroupId();
363	                String reqVersion = req.getVersion();
364	                if ((reqGroup == null || reqGroup.equals(tag.getChildValue("groupId").orElse(null))) &&
365	                        req.getArtifactId().equals(tag.getChildValue("artifactId").orElse(null)) &&
366	                        (reqVersion == null || reqVersion.equals(tag.getChildValue("version").orElse(null))) &&
367	                        (req.getClassifier() == null || req.getClassifier().equals(tag.getChildValue("classifier").orElse(null)))) {
368	                    return resolvedDependency;
369	                }
370	            }
371	        }
372	        return null;
373	    }
374	
375	    public @Nullable ResolvedManagedDependency findManagedDependency(Xml.Tag tag) {
376	        String groupId = getResolutionResult().getPom().getValue(tag.getChildValue("groupId")
377	                .orElse(getResolutionResult().getPom().getGroupId()));
378	        String artifactId = getResolutionResult().getPom().getValue(tag.getChildValue("artifactId").orElse(""));
379	        String classifier = getResolutionResult().getPom().getValue(tag.getChildValue("classifier").orElse(null));
380	        String type = getResolutionResult().getPom().getValue(tag.getChildValue("type").orElse(null));
381	        if (groupId != null && artifactId != null) {
382	            return findManagedDependency(groupId, artifactId, classifier, type);
383	        }
384	        return null;
385	    }
386	
387	    public @Nullable ResolvedManagedDependency findManagedDependency(String groupId, String artifactId) {
388	        return findManagedDependency(groupId, artifactId, null, null);
389	    }
390	
391	    private @Nullable ResolvedManagedDependency findManagedDependency(String groupId, String artifactId, @Nullable String classifier, @Nullable String type) {
392	        for (ResolvedManagedDependency d : getResolutionResult().getPom().getDependencyManagement()) {
393	            if (groupId.equals(d.getGroupId()) &&
394	                    artifactId.equals(d.getArtifactId()) &&
395	                    (classifier == null || classifier.equals(d.getClassifier())) &&
396	                    (type == null || type.equals(d.getType()))) {
397	                return d;
398	            }
399	        }
400	        return null;
401	    }
402	
403	    public @Nullable ResolvedManagedDependency findManagedDependency(Xml.Tag tag, @Nullable Scope inClasspathOf) {
404	        Scope tagScope = Scope.fromName(tag.getChildValue("scope").orElse(null));
405	        if (inClasspathOf != null && tagScope != inClasspathOf && !tagScope.isInClasspathOf(inClasspathOf)) {
406	            return null;
407	        }
408	        return findManagedDependency(tag);
409	    }
410	
411	    public @Nullable ResolvedDependency findDependency(Xml.Tag tag, @Nullable Scope inClasspathOf) {
412	        Scope tagScope = Scope.fromName(tag.getChildValue("scope").orElse("compile"));
413	        if (inClasspathOf != null && tagScope != inClasspathOf && !tagScope.isInClasspathOf(inClasspathOf)) {
414	            return null;
415	        }
416	        for (Map.Entry<Scope, List<ResolvedDependency>> scope : getResolutionResult().getDependencies().entrySet()) {
417	            if (inClasspathOf == null || scope.getKey() == inClasspathOf || scope.getKey().isInClasspathOf(inClasspathOf)) {
418	                for (ResolvedDependency d : scope.getValue()) {
419	                    if (tag.getChildValue("groupId").orElse(getResolutionResult().getPom().getGroupId()).equals(d.getGroupId()) &&
420	                            tag.getChildValue("artifactId").orElse(getResolutionResult().getPom().getArtifactId()).equals(d.getArtifactId())) {
421	                        return d;
422	                    }
423	                }
424	            }
425	        }
426	        return null;
427	    }
428	
429	    /**
430	     * Finds dependencies in the model that match the provided group and artifact ids.
431	     * <p>
432	     * Note: The list may contain the same dependency multiple times, if it is present in multiple scopes.
433	     *
434	     * @param groupId    The groupId to match
435	     * @param artifactId The artifactId to match.
436	     * @return dependencies (including transitive dependencies) with any version matching the provided group and artifact id, if any.
437	     */
438	    public List<ResolvedDependency> findDependencies(String groupId, String artifactId) {
439	        return getResolutionResult().findDependencies(groupId, artifactId, null);
440	    }
441	
442	    /**
443	     * Finds dependencies in the model that match the given predicate.
444	     *
445	     * @param matcher A dependency test
446	     * @return dependencies (including transitive dependencies) with any version matching the given predicate.
447	     */
448	    public Collection<ResolvedDependency> findDependencies(Predicate<ResolvedDependency> matcher) {
449	        List<ResolvedDependency> found = null;
450	        for (List<ResolvedDependency> scope : getResolutionResult().getDependencies().values()) {
451	            for (ResolvedDependency d : scope) {
452	                if (matcher.test(d)) {
453	                    if (found == null) {
454	                        found = new ArrayList<>();
455	                    }
456	                    found.add(d);
457	                }
458	            }
459	        }
460	        return found == null ? emptyList() : found;
461	    }
462	
463	    public MavenMetadata downloadMetadata(String groupId, String artifactId, ExecutionContext ctx) throws MavenDownloadingException {
464	        return downloadMetadata(groupId, artifactId, null, ctx);
465	    }
466	
467	    public MavenMetadata downloadMetadata(String groupId, String artifactId, @Nullable ResolvedPom containingPom, ExecutionContext ctx) throws MavenDownloadingException {
468	        MavenExecutionContextView mctx = MavenExecutionContextView.view(ctx);
469	        Optional<MavenSettings> maybeSettings = Optional.ofNullable(mctx.effectiveSettings(getResolutionResult()));
470	        List<String> activeProfiles = maybeSettings.map(MavenSettings::getActiveProfiles)
471	                .map(MavenSettings.ActiveProfiles::getActiveProfiles)
472	                .orElse(null);
473	        return new MavenPomDownloader(getResolutionResult().getProjectPoms(), ctx, maybeSettings.orElse(null), activeProfiles)
474	                .downloadMetadata(new GroupArtifact(groupId, artifactId), containingPom, getResolutionResult().getPom().getRepositories());
475	    }
476	
477	    public MavenMetadata downloadPluginMetadata(String groupId, String artifactId, ExecutionContext ctx) throws MavenDownloadingException {
478	        return downloadPluginMetadata(groupId, artifactId, null, ctx);
479	    }
