481	    public MavenMetadata downloadPluginMetadata(String groupId, String artifactId, @Nullable ResolvedPom containingPom, ExecutionContext ctx) throws MavenDownloadingException {
482	        MavenExecutionContextView mctx = MavenExecutionContextView.view(ctx);
483	        Optional<MavenSettings> maybeSettings = Optional.ofNullable(mctx.effectiveSettings(getResolutionResult()));
484	        List<String> activeProfiles = maybeSettings.map(MavenSettings::getActiveProfiles)
485	                .map(MavenSettings.ActiveProfiles::getActiveProfiles)
486	                .orElse(null);
487	        return new MavenPomDownloader(getResolutionResult().getProjectPoms(), ctx, maybeSettings.orElse(null), activeProfiles)
488	                .downloadMetadata(new GroupArtifact(groupId, artifactId), containingPom, getResolutionResult().getPom().getPluginRepositories());
489	    }
490	
491	    /**
492	     * Does the current tag can contain groupId, artifactId and version?
493	     */
494	    @SuppressWarnings("unused")
495	    public boolean isDependencyLikeTag() {
496	        return isManagedDependencyTag() || isDependencyTag() || isPluginTag();
497	    }
498	
499	    public @Nullable Plugin findPlugin(Xml.Tag tag) {
500	        return findPlugin(tag, getResolutionResult().getPom().getPlugins());
501	    }
502	
503	    public @Nullable Plugin findManagedPlugin(Xml.Tag tag) {
504	        return findPlugin(tag, getResolutionResult().getPom().getPluginManagement());
505	    }
506	
507	    private static @Nullable Plugin findPlugin(Xml.Tag tag, List<Plugin> plugins) {
508	        String tagGroupId = tag.getChildValue("groupId").orElse(PLUGIN_DEFAULT_GROUPID);
509	        String tagArtifactId = tag.getChildValue("artifactId").orElse(null);
510	        String tagVersion = tag.getChildValue("version").orElse(null);
511	        for (Plugin resolvedPlugin : plugins) {
512	            String resGroup = resolvedPlugin.getGroupId();
513	            String resArtifactId = resolvedPlugin.getArtifactId();
514	            String resVersion = resolvedPlugin.getVersion();
515	            if (resGroup.equals(tagGroupId) &&
516	                    resArtifactId.equals(tagArtifactId) &&
517	                    (resVersion == null || tagVersion == null || resVersion.equals(tagVersion))) {
518	                return resolvedPlugin;
519	            }
520	        }
521	        return null;
522	    }
523	}
